                del agents_map[agent_id]['subagents']

# 保存修改
with open('/root/.openclaw/openclaw.json', 'w', encoding='utf-8') as f:
    json.dump(config, f, indent=2, ensure_ascii=False)

print("✅ 三省六部配置已按照项目模板更新")
print("\n更新内容：")
print("- 中书省：移除subagents配置，专注于决策起草")
print("- 门下省：移除subagents配置，专注于审核追问")
print("- 尚书省：保留subagents配置，可调用六部和御史台")
print("- 御史台/六部：无subagents配置，专注于各自职责")
print("- 所有workspace路径已更新为用户目录")
EOF

